use chrono::Utc;
use std::collections::{BTreeMap, HashSet};
use symphony::domain::*;

// ── ServerConfig default fix (T01 must-have) ───────────────────────────

#[test]
fn server_config_default_host_is_localhost() {
    let cfg = ServerConfig::default();
    assert_eq!(cfg.host, "127.0.0.1");
    assert!(cfg.port.is_none());
}

// ── Runtime entity construction (T01 scope) ────────────────────────────

#[test]
fn run_attempt_construction_and_serialization() {
    let ra = RunAttempt {
        issue_id: "id-1".into(),
        issue_identifier: "PROJ-1".into(),
        attempt: None,
        workspace_path: "/tmp/ws".into(),
        started_at: Utc::now(),
        status: "running".into(),
        error: None,
        worker_host: None,
    };
    let json = serde_json::to_string(&ra).unwrap();
    let deser: RunAttempt = serde_json::from_str(&json).unwrap();
    assert_eq!(deser.issue_id, "id-1");
    assert!(deser.attempt.is_none());
}

#[test]
fn live_session_token_defaults() {
    // Token counters should default to 0 when missing from JSON
    let json = r#"{
        "session_id": "s1",
        "thread_id": "t1",
        "turn_id": "turn1",
        "started_at": "2026-01-01T00:00:00Z"
    }"#;
    let ls: LiveSession = serde_json::from_str(json).unwrap();
    assert_eq!(ls.codex_input_tokens, 0);
    assert_eq!(ls.codex_output_tokens, 0);
    assert_eq!(ls.codex_total_tokens, 0);
    assert_eq!(ls.last_reported_input_tokens, 0);
    assert_eq!(ls.last_reported_output_tokens, 0);
    assert_eq!(ls.last_reported_total_tokens, 0);
    assert_eq!(ls.turn_count, 0);
}

#[test]
fn retry_entry_construction() {
    let re = RetryEntry {
        issue_id: "id-2".into(),
        identifier: "PROJ-2".into(),
        attempt: 1,
        due_at_ms: 1234567890,
        timer_handle: None,
        error: Some("timeout".into()),
        worker_host: None,
        workspace_path: Some("/tmp/ws2".into()),
    };
    assert_eq!(re.attempt, 1);
    assert_eq!(re.error.as_deref(), Some("timeout"));
}

// ── Snapshot types (T01 must-have: BTreeMap for deterministic JSON) ────

#[test]
fn orchestrator_snapshot_serialization_deterministic() {
    let snap = OrchestratorSnapshot {
        poll_interval_ms: 30_000,
        max_concurrent_agents: 5,
        running: BTreeMap::new(),
        claimed: HashSet::new(),
        retry_queue: vec![],
        completed: HashSet::new(),
        codex_totals: CodexTotals::default(),
        codex_rate_limits: None,
        polling: PollingSnapshot {
            checking: false,
            next_poll_in_ms: 15_000,
            poll_interval_ms: 30_000,
        },
    };
    let json = serde_json::to_string(&snap).unwrap();
    assert!(json.contains("\"poll_interval_ms\":30000"));
    // BTreeMap ensures deterministic ordering — verify it's valid JSON
    let _: serde_json::Value = serde_json::from_str(&json).unwrap();
}

// ── AgentEvent enum (T01 must-have) ───────────────────────────────────

#[test]
fn agent_event_variant_construction_and_debug() {
    let events: Vec<AgentEvent> = vec![
        AgentEvent::SessionStarted {
            timestamp: Utc::now(),
            codex_app_server_pid: Some("1234".into()),
            session_id: "sess-1".into(),
        },
        AgentEvent::StartupFailed {
            timestamp: Utc::now(),
            codex_app_server_pid: None,
            error: "port in use".into(),
        },
        AgentEvent::TurnCompleted {
            timestamp: Utc::now(),
            codex_app_server_pid: None,
            turn_id: "t1".into(),
            message: Some("done".into()),
        },
        AgentEvent::TurnFailed {
            timestamp: Utc::now(),
            codex_app_server_pid: None,
            turn_id: "t1".into(),
            error: "crash".into(),
        },
        AgentEvent::TurnCancelled {
            timestamp: Utc::now(),
            codex_app_server_pid: None,
            turn_id: "t1".into(),
        },
        AgentEvent::TurnEndedWithError {
            timestamp: Utc::now(),
            codex_app_server_pid: None,
            turn_id: "t1".into(),
            error: "oops".into(),
        },
        AgentEvent::TurnInputRequired {
            timestamp: Utc::now(),
            codex_app_server_pid: None,
            turn_id: "t1".into(),
            prompt: None,
        },
        AgentEvent::ApprovalAutoApproved {
            timestamp: Utc::now(),
            codex_app_server_pid: None,
            tool_call: "shell".into(),
        },
        AgentEvent::UnsupportedToolCall {
            timestamp: Utc::now(),
            codex_app_server_pid: None,
            tool_name: "unknown_tool".into(),
        },
        AgentEvent::Notification {
            timestamp: Utc::now(),
            codex_app_server_pid: None,
            message: "info".into(),
        },
        AgentEvent::OtherMessage {
            timestamp: Utc::now(),
            codex_app_server_pid: None,
            raw: serde_json::json!({"type": "unknown"}),
        },
        AgentEvent::Malformed {
            timestamp: Utc::now(),
            codex_app_server_pid: None,
            raw_text: "bad data".into(),
            parse_error: "expected json".into(),
        },
    ];
    // All 12 variants constructed; Debug formatting works
    assert_eq!(events.len(), 12);
    for event in &events {
        let debug = format!("{:?}", event);
        assert!(!debug.is_empty());
    }
}

// ── CodexTotals default ───────────────────────────────────────────────

#[test]
fn codex_totals_default_is_zero() {
    let t = CodexTotals::default();
    assert_eq!(t.input_tokens, 0);
    assert_eq!(t.output_tokens, 0);
    assert_eq!(t.total_tokens, 0);
    assert_eq!(t.seconds_running, 0.0);
}

